**Idea — binary exponentiation**: Express the exponent in binary. Square the base each step; if the current bit is 1, multiply the running product.

```javascript
function myPow(x, n) {
  if (n === 0) return 1;
  let N = n;
  if (N < 0) { x = 1 / x; N = -N; }
  let result = 1, base = x;
  while (N > 0) {
    if (N % 2 === 1) result = result * base;
    base = base * base;
    N = Math.floor(N / 2);
