editorial:
**Idea — long division with a remainder map**: Compute integer part, then keep dividing the remainder by 10. Each remainder is uniquely tied to a position in the output; if we ever see the same remainder twice, the digits between are the recurring block.

```javascript
function fractionToDecimal(numerator, denominator) {
  if (numerator === 0) return '0';
  let res = '';
  if ((numerator < 0) !== (denominator < 0)) res += '-';
  let n = Math.abs(numerator);
  let d = Math.abs(denominator);
  res += Math.floor(n / d).toString();
  let rem = n % d;
  if (rem === 0) return res;
  res += '.';
  const map = new Map();
  while (rem !== 0) {
    if (map.has(rem)) {
      const idx = map.get(rem);
      return res.slice(0, idx) + '(' + res.slice(idx) + ')';
    }
    map.set(rem, res.length);
    rem *= 10;
    res += Math.floor(rem / d).toString();
    rem = rem % d;
  }
  return res;
}
```

**Time**: O(d) worst case (number of distinct remainders ≤ d). **Space**: O(d).

